mapper.select:
SELECT COUNT(*) > 0
FROM progist.bid_favorites
WHERE user_seq = #{userSeq}
  AND bid_no = #{bidNo}
  AND bid_ord = #{bidOrd}
  AND announce_date = #{announceDate}

mapper.delete:
DELETE FROM progist.bid_favorites
WHERE user_seq = #{userSeq}
  AND bid_no = #{bidNo}
  AND bid_ord = #{bidOrd}
  AND announce_date = #{announceDate}
